import argparse
import os
import sys

def session_sync():
    print("--- SESSION SYNC (Engine Layer) ---")
    if os.path.exists("task_plan.md"):
        print("[Task Plan Summary]")
        with open("task_plan.md", "r") as f:
            print("\n".join([line for line in f if "[ ]" in line][:5]))
    print("\n[Last 5 Progress Entries]")
    if os.path.exists("progress.md"):
        with open("progress.md", "r") as f:
            print("\n".join(f.readlines()[-5:]))

def milestone_sync():
    print("--- MILESTONE GATE (Spec Layer) ---")
    print("ACTION REQUIRED: Verify docs/milestones/ against implementation.")
    if os.path.exists("findings.md"):
        print("\nFound open findings. Check findings.md and archive to Knowledge Layer.")

def audit():
    print("--- GLOBAL INTEGRITY (Spec vs Engine) ---")
    files = ["INDEX.md", "task_plan.md", "ROADMAP.md"]
    missing = [f for f in files if not os.path.exists(f)]
    if missing:
        print(f"Warning: Missing files: {missing}")
    else:
        print("Required hierarchy files found.")
    print("Verification complete.")

if __name__ == "__main__":
    parser = argparse.ArgumentParser()
    parser.add_argument("tier", choices=["session", "milestone", "audit"])
    args = parser.parse_args()

    if args.tier == "session": session_sync()
    elif args.tier == "milestone": milestone_sync()
    elif args.tier == "audit": audit()
